// =============================================================================
// ASim_AbstractEvent  —  ASIM-style normalizing parser for Abstract Security
// -----------------------------------------------------------------------------
// Source : AbstractEventLogs_CL  (the custom table the Sentinel Destination
//          template creates; default schema = TimeGenerated, Message,
//          AbstractEvent:dynamic that carries the Abstract Common Schema event).
// Purpose: project the Abstract Common Schema (ACS) into ASIM-aligned column
//          names so Abstract-delivered data lights up Microsoft's ASIM-based
//          analytics, and add convenient ACS pass-through fields.
//
// Deploy : Logs > New query > paste > Save as function, Function alias:
//          ASim_AbstractEvent   (Legacy category: ASIM)
//          Then query it like a table:  ASim_AbstractEvent | take 50
//
// Field mapping is grounded in the live ACS catalog (473 fields). If you ingest
// the full all_fields schema as explicit columns instead of the dynamic
// AbstractEvent column, swap `e.<field>` for `columnname_s` accordingly.
// =============================================================================
let ASim_AbstractEvent = (disabled: bool = false) {
    AbstractEventLogs_CL
    | where not(disabled)
    | extend e = AbstractEvent
    // ---- core / ASIM common ----
    | extend
        EventVendor      = tostring(e.vendor),
        EventProduct     = tostring(e.product),
        EventType        = tostring(e.type),
        EventResult      = tostring(e.action),
        EventSeverity    = tostring(e.severity),
        EventMessage     = coalesce(tostring(e.message), Message),
        EventCount       = toreal(e.aggregation_count),
        EventRiskScore   = toreal(e.risk_score)
    // ---- network ----
    | extend
        SrcIpAddr        = coalesce(tostring(e.source_ipv4), tostring(e.source_ipv6), tostring(e.source_address)),
        DstIpAddr        = coalesce(tostring(e.dest_ipv4), tostring(e.dest_ipv6), tostring(e.dest_address)),
        SrcPortNumber    = toint(e.source_port),
        DstPortNumber    = toint(e.dest_port),
        DvcIpAddr        = coalesce(tostring(e.host_ipv4), tostring(e.host_ipv6), tostring(e.host_address)),
        DvcHostname      = tostring(e.host_name)
    // ---- identity ----
    | extend
        ActorUsername    = coalesce(tostring(e.user_name), tostring(e.user_id)),
        TargetUsername   = tostring(e['user.target.name']),
        UserAgent        = tostring(e.user_agent)
    // ---- correlation back to Abstract ----
    | extend
        AbstractEventId    = tostring(e.id),
        AbstractIdentity   = tostring(e.identity),
        AbstractMatchedRules = e.matched_rules,
        AbstractTags       = e.tags,
        AbstractTimestamp  = todatetime(e['@timestamp'])
    | project-reorder
        TimeGenerated, EventVendor, EventProduct, EventType, EventResult, EventSeverity,
        SrcIpAddr, DstIpAddr, SrcPortNumber, DstPortNumber, ActorUsername, EventMessage,
        EventRiskScore, AbstractEventId, AbstractIdentity
};
ASim_AbstractEvent
